// ===== FIXED: index aur loading ko upar declare kiya
// pehle yeh neeche the, is wajah se categories me infinite scroll break ho raha tha

let index = 30;
let loading = false;

// yeh variable currently active albums ko store karega
let currentAlbums = [...albumData];


// Theme toggle
function toggleDarkMode() {
    document.documentElement.classList.toggle("dark");
}


// ================= CATEGORY TABS =================
const tabs = document.querySelectorAll(".tab-btn");

tabs.forEach(tab => {
    tab.addEventListener("click", () => {

        tabs.forEach(t => t.classList.remove("active-tab"));
        tab.classList.add("active-tab");

        const selectedCategory = tab.textContent.trim();
        const grid = document.querySelector(".masonry-grid");

        // ❌ FIX: yahan "gridx" likha tha, jiski wajah se JS crash ho raha tha
        grid.innerHTML = "";
        index = 0;
        loading = false;

        const loader = document.getElementById("loadingIndicator");
        const endMessage = document.getElementById("endMessage");
        if (loader) loader.style.display = "flex";
        if (endMessage) endMessage.style.opacity = "0";

        currentAlbums =
            selectedCategory === "All"
                ? [...albumData]
                : albumData.filter(album => album.category === selectedCategory);

        const INITIAL_LOAD = 30; // ⚠️ as you requested – unchanged
        currentAlbums.slice(0, INITIAL_LOAD).forEach(album => {
            grid.insertAdjacentHTML("beforeend", createAlbumCard(album));
        });

        index = INITIAL_LOAD;
        ensureScrollable();
    });
});


// ================= CURSOR GLOW =================
const blob = document.getElementById("cursor-blob");
document.addEventListener("mousemove", (e) => {
    const blobSize = 380;
    blob.style.transform =
        `translate(${e.clientX - blobSize / 2}px, ${e.clientY - blobSize / 2}px)`;
});


// ================= SEARCH =================
const searchInput = document.getElementById("searchInput");

searchInput.addEventListener("input", () => {
    const query = searchInput.value.toLowerCase().trim();
    const grid = document.querySelector(".masonry-grid");

    grid.innerHTML = "";
    index = 0;
    loading = false;

    const activeTab = document.querySelector(".tab-btn.active-tab");
    const selectedCategory = activeTab ? activeTab.textContent.trim() : "All";

    let filtered = albumData;

    if (selectedCategory !== "All") {
        filtered = filtered.filter(album => album.category === selectedCategory);
    }

    if (query !== "") {
        filtered = filtered.filter(album =>
            album.title.toLowerCase().includes(query) ||
            album.artist.toLowerCase().includes(query)
        );
    }

    currentAlbums = filtered;

    const INITIAL_LOAD = 30;
    currentAlbums.slice(0, INITIAL_LOAD).forEach(album => {
        grid.insertAdjacentHTML("beforeend", createAlbumCard(album));
    });

    index = INITIAL_LOAD;
    ensureScrollable();
});


// ================= CARD =================
function createAlbumCard(album) {
    return `
    <div class="masonry-item group cursor-pointer"
         onclick="openPlayer('${album.link}')">

        <div class="flex flex-col gap-4 rounded-2xl bg-white dark:bg-gray-900 p-4 shadow-sm transition-transform hover:-translate-y-1">
            <div class="relative w-full overflow-hidden rounded-xl bg-gray-100 dark:bg-gray-800">
                <img src="${album.image}"
                     class="w-full h-auto object-cover transition-transform duration-700 group-hover:scale-105">
            </div>
            <div>
                <p class="text-xl font-semibold">${album.title}</p>
                <span class="text-sm text-[#617589] dark:text-gray-400">${album.artist}</span>
            </div>
        </div>
    </div>`;
}


// ================= INITIAL LOAD =================
function loadInitialAlbums() {
    const grid = document.querySelector(".masonry-grid");
    const INITIAL_LOAD = 30;

    currentAlbums.slice(0, INITIAL_LOAD).forEach(album => {
        grid.insertAdjacentHTML("beforeend", createAlbumCard(album));
    });

    index = INITIAL_LOAD;
}

loadInitialAlbums();
ensureScrollable();


// ================= ENSURE SCROLL =================
function ensureScrollable() {
    const grid = document.querySelector(".masonry-grid");

    while (
        document.documentElement.scrollHeight <= window.innerHeight &&
        index < currentAlbums.length
    ) {
        currentAlbums.slice(index, index + 4).forEach(album => {
            grid.insertAdjacentHTML("beforeend", createAlbumCard(album));
        });
        index += 4;
    }
}


// ================= INFINITE SCROLL =================
window.addEventListener("scroll", () => {
    const loader = document.getElementById("loadingIndicator");
    const endMessage = document.getElementById("endMessage");

    if (window.innerHeight + window.scrollY >= document.documentElement.scrollHeight - 200) {

        if (!loading && index < currentAlbums.length) {
            loading = true;
            if (loader) loader.style.opacity = "1";

            setTimeout(() => {
                const grid = document.querySelector(".masonry-grid");

                currentAlbums.slice(index, index + 4).forEach(album => {
                    grid.insertAdjacentHTML("beforeend", createAlbumCard(album));
                });

                index += 4;
                loading = false;
                if (loader) loader.style.opacity = "0";
            }, 1200);

        } else if (index >= currentAlbums.length) {
            if (loader) loader.style.display = "none";
            if (endMessage) endMessage.style.opacity = "1";
        }
    }
});

document.getElementById("year").textContent = new Date().getFullYear();


// ================= PLAYER LOGIC =================
let savedScrollY = 0;

function openPlayer(youtubeUrl) {
    savedScrollY = window.scrollY;

    let videoId = "";
    if (youtubeUrl.includes("youtu.be/")) {
        videoId = youtubeUrl.split("youtu.be/")[1].split("?")[0];
    } else if (youtubeUrl.includes("watch?v=")) {
        videoId = youtubeUrl.split("v=")[1].split("&")[0];
    }

    history.pushState({ playerOpen: true }, "", "#player");

    document.querySelector(".masonry-grid").style.display = "none";
    document.getElementById("playerView").classList.remove("hidden");

    document.getElementById("ytPlayer").src =
        `https://www.youtube.com/embed/${videoId}?autoplay=1`;

    window.scrollTo(0, 0);
}

function closePlayer() {
    document.getElementById("playerView").classList.add("hidden");
    document.querySelector(".masonry-grid").style.display = "";
    document.getElementById("ytPlayer").src = "";
    window.scrollTo(0, savedScrollY);
}

window.addEventListener("popstate", (e) => {
    if (!e.state || !e.state.playerOpen) {
        closePlayer();
    }
});

// ================= PROFILE MENU (ONLY FIX ADDED)  Logout fix isse hua hai=================
const profileToggle = document.getElementById("profileToggle");
const profileCard = document.getElementById("profileCard");

if (profileToggle && profileCard) {
    profileToggle.addEventListener("click", (e) => {
        e.stopPropagation();
        profileCard.classList.toggle("show");
    });

    document.addEventListener("click", (e) => {
        if (!profileCard.contains(e.target) && !profileToggle.contains(e.target)) {
            profileCard.classList.remove("show");
        }
    });
}

const aiButton = document.getElementById("aiButton");
const aiBox = document.getElementById("aiBox");

aiButton.addEventListener("click", () => {
    aiBox.style.display = aiBox.style.display === "block" ? "none" : "block";
});

const topButton = document.getElementById("topButton");

topButton.addEventListener("click", () => {
    window.scrollTo({
        top: 0,
        behavior: "smooth"
    });
});

document.getElementById("detectMoodBtn").onclick = () => {
    const text = document.getElementById("moodInput").value.toLowerCase();
    const moodResult = document.getElementById("moodResult");

    let mood = "Chill";

    if (text.includes("sad") || text.includes("bad") || text.includes("hurt"))
        mood = "Sad";

    else if (text.includes("happy") || text.includes("excited") || text.includes("awesome"))
        mood = "Energetic";

    else if (text.includes("tired") || text.includes("calm") || text.includes("relax"))
        mood = "Chill";

    else if (text.includes("study") || text.includes("focus") || text.includes("work"))
        mood = "Focus";

    moodResult.innerText = "Mood: " + mood;

    applyMoodEffects(mood);
};
